h-mark:
width: 28px; height: 28px;
    background: var(--black);
    border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    color: var(--paper);
    font-family: Georgia, serif;
    font-size: 16px;
    font-weight: 700;
    letter-spacing: -0.5px;

chip:
display: inline-flex;
    align-items: center;
    gap: 4px;
    background: var(--sand);
    padding: 6px 12px;
    border-radius: 500px;
    font-size: 12px;
    font-weight: 500;
    color: var(--black);

prompt-q:
font-family: var(--display);
    font-size: 14px;
    font-weight: 500;
    color: var(--graphite);
    font-style: italic;
    letter-spacing: -0.2px;
    margin-bottom: 8px;

prompt-a:
font-family: var(--display);
    font-size: 17px;
    font-weight: 700;
    color: var(--black);
    line-height: 1.25;
    letter-spacing: -0.3px;

heart-tap:
position: absolute;
    bottom: 12px; right: 12px;
    width: 36px; height: 36px;
    border-radius: 50%;
    background: var(--paper);
    border: 1px solid var(--black);
    display: flex; align-items: center; justify-content: center;

ab-btn:
width: 52px; height: 52px;
    border-radius: 50%;
    background: var(--paper);
    border: 1.5px solid var(--black);
    display: flex; align-items: center; justify-content: center;
    box-shadow: 0 4px 12px rgba(28,20,10,0.10);
